('ph-bi-foundations', NULL, 100, 'phase', NULL, NULL, NULL, 'BI Foundations and Business Context', 'Build the business intelligence mindset, analytics vocabulary, stakeholder focus, and decision-support context required for BI work.', 'This node builds practical BI analyst capability in bi foundations and business context.', 'trunk', 'ph-bi-foundations', 1, 0, 14, 'beginner', 100, NULL, NULL, '{"source": "roadmap.sh/bi-analyst", "visualRule": "main_spine"}'::jsonb, true, false, '["Explain bi foundations and business context in a BI context", "Apply bi foundations and business context to a realistic business problem"]'::jsonb, '["Complete the learning resources for BI Foundations and Business Context", "Produce a small artifact or notes showing applied understanding"]'::jsonb),
('grp-bi-role-mindset', 'ph-bi-foundations', 110, 'choice_group', NULL, 'complete_all', NULL, 'BI Role, Mindset, and Analytics Lifecycle', 'Group of related BI skills for bi role, mindset, and analytics lifecycle.', 'This node builds practical BI analyst capability in bi role, mindset, and analytics lifecycle.', 'side', 'ph-bi-foundations', 1, 10, 2, 'beginner', 110, NULL, NULL, '{"selectionType": "complete_all", "source": "roadmap.sh/bi-analyst"}'::jsonb, true, false, '["Explain bi role, mindset, and analytics lifecycle in a BI context", "Apply bi role, mindset, and analytics lifecycle to a realistic business problem"]'::jsonb, '["Complete the learning resources for BI Role, Mindset, and Analytics Lifecycle", "Produce a small artifact or notes showing applied understanding"]'::jsonb),
