-- ============================================================
-- business-intelligence-roadmap-sh-full-detailed-seed-v1.sql
-- Full detailed Business Intelligence Analyst roadmap seed based on roadmap.sh/bi-analyst.
-- Idempotent seed: safe to rerun in the same database/session.
-- ============================================================

-- Shared-skill aliases normalized against core/shared-skills.seed.sql.
BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

DELETE FROM public.progress_event WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.title IN ('Business Intelligence Analyst Roadmap', 'Business Intelligence Roadmap', 'BI Analyst Roadmap', 'Business Intelligence Analyst Roadmap - roadmap.sh Full Detailed Seed'));
DELETE FROM public.user_node_progress WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.title IN ('Business Intelligence Analyst Roadmap', 'Business Intelligence Roadmap', 'BI Analyst Roadmap', 'Business Intelligence Analyst Roadmap - roadmap.sh Full Detailed Seed'));
DELETE FROM public.roadmap_enrollment WHERE roadmap_version_id IN (SELECT rv.roadmap_version_id FROM public.roadmap_version rv JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.title IN ('Business Intelligence Analyst Roadmap', 'Business Intelligence Roadmap', 'BI Analyst Roadmap', 'Business Intelligence Analyst Roadmap - roadmap.sh Full Detailed Seed'));
DELETE FROM public.roadmap WHERE title IN ('Business Intelligence Analyst Roadmap', 'Business Intelligence Roadmap', 'BI Analyst Roadmap', 'Business Intelligence Analyst Roadmap - roadmap.sh Full Detailed Seed');

    'Business Intelligence Analyst',
    'business-intelligence-analyst',
    'Business intelligence analyst path covering business context, spreadsheets, SQL, statistics, data modeling, BI tools, visualization, Python, data preparation, cloud BI, governance, advanced analytics, delivery operations, and portfolio work.',
    'Data',
    true
) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, category = EXCLUDED.category, is_active = true, updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (SELECT career_role_id FROM public.career_role WHERE slug = 'business-intelligence-analyst'), inserted_roadmap AS (
    SELECT career_role_id, 'Business Intelligence Analyst Roadmap', 'A structured learning path for becoming a business intelligence analyst, covering business context, spreadsheets, SQL, statistics, data modeling, BI tools, data visualization, Python analytics, data preparation, cloud BI platforms, governance, advanced analytics, BI operations, and portfolio-ready capstone work.', 'template', 'static', 'public' FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
    SELECT roadmap_id, 1, 'published', 'Business Intelligence Analyst Roadmap v1', 'A practical BI analyst roadmap that moves from business and data foundations to production-ready dashboards, governed metrics, analysis automation, stakeholder communication, and capstone portfolio work.', 420, 'none', '{}'::jsonb, 'TB', 'custom', now() FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
) SELECT roadmap_id, roadmap_version_id FROM inserted_version;

-- Skills.
DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (slug text PRIMARY KEY, name text NOT NULL, category text NOT NULL, description text NOT NULL) ON COMMIT DROP;

SELECT ss.name, ss.slug, ss.category, ss.description, true FROM seed_skill ss WHERE NOT EXISTS (SELECT 1 FROM public.skill s WHERE s.slug = ss.slug OR s.name = ss.name);

-- Learning resources.
DROP TABLE IF EXISTS seed_resource;
CREATE TEMP TABLE seed_resource (resource_key text PRIMARY KEY, title text NOT NULL, url text NOT NULL, resource_type text NOT NULL, description text NOT NULL, provider text NOT NULL, difficulty_level text NOT NULL) ON COMMIT DROP;
;

UPDATE public.learning_resource lr SET title = sr.title, resource_type = sr.resource_type, description = sr.description, provider = sr.provider, difficulty_level = sr.difficulty_level, language_code = 'en', verification_status = 'verified', updated_at = now() FROM (SELECT DISTINCT ON (url) title, url, resource_type, description, provider, difficulty_level FROM seed_resource ORDER BY url, resource_key) sr WHERE lr.url = sr.url;
SELECT sr.title, sr.url, sr.resource_type, sr.description, sr.provider, sr.difficulty_level, 'en', 'verified' FROM (SELECT DISTINCT ON (url) title, url, resource_type, description, provider, difficulty_level FROM seed_resource ORDER BY url, resource_key) sr WHERE NOT EXISTS (SELECT 1 FROM public.learning_resource lr WHERE lr.url = sr.url);

-- Roadmap nodes.
DROP TABLE IF EXISTS seed_node;
CREATE TEMP TABLE seed_node (node_key text PRIMARY KEY, parent_key text, order_index int NOT NULL, node_type text NOT NULL, checkpoint_type text, selection_type text, required_count int, title text NOT NULL, description text NOT NULL, reason text NOT NULL, layout_role text, layout_group text, layout_rank int, layout_order int, estimated_hours int, difficulty_level text, priority int, position_x int, position_y int, metadata jsonb, is_required boolean, is_trackable boolean, learning_outcomes jsonb, completion_criteria jsonb, node_id uuid DEFAULT gen_random_uuid()) ON COMMIT DROP;

SELECT sn.node_id, m.roadmap_version_id, parent.node_id, sn.node_key, sn.node_type, sn.checkpoint_type, sn.selection_type, sn.required_count, sn.title, sn.description, sn.reason, sn.order_index, sn.layout_role, sn.layout_group, sn.layout_rank, sn.layout_order, sn.estimated_hours, sn.difficulty_level, sn.priority, sn.position_x, sn.position_y, sn.metadata, sn.is_required, sn.is_trackable, sn.learning_outcomes, sn.completion_criteria FROM seed_node sn CROSS JOIN seed_roadmap_map m LEFT JOIN seed_node parent ON parent.node_key = sn.parent_key
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET parent_node_id = EXCLUDED.parent_node_id, node_type = EXCLUDED.node_type, checkpoint_type = EXCLUDED.checkpoint_type, selection_type = EXCLUDED.selection_type, required_count = EXCLUDED.required_count, title = EXCLUDED.title, description = EXCLUDED.description, reason = EXCLUDED.reason, order_index = EXCLUDED.order_index, layout_role = EXCLUDED.layout_role, layout_group = EXCLUDED.layout_group, layout_rank = EXCLUDED.layout_rank, layout_order = EXCLUDED.layout_order, estimated_hours = EXCLUDED.estimated_hours, difficulty_level = EXCLUDED.difficulty_level, priority = EXCLUDED.priority, position_x = EXCLUDED.position_x, position_y = EXCLUDED.position_y, metadata = EXCLUDED.metadata, is_required = EXCLUDED.is_required, is_trackable = EXCLUDED.is_trackable, learning_outcomes = EXCLUDED.learning_outcomes, completion_criteria = EXCLUDED.completion_criteria;

-- Node-skill mappings.
DROP TABLE IF EXISTS seed_node_skill;
CREATE TEMP TABLE seed_node_skill (node_key text NOT NULL, skill_slug text NOT NULL) ON COMMIT DROP;

SELECT DISTINCT rn.roadmap_node_id, s.skill_id FROM seed_node_skill sns JOIN seed_node sn ON sn.node_key = sns.node_key JOIN seed_roadmap_map m ON true JOIN public.roadmap_node rn ON rn.roadmap_version_id = m.roadmap_version_id AND rn.slug = sn.node_key JOIN seed_skill ss ON ss.slug = sns.skill_slug JOIN public.skill s ON s.slug = ss.slug OR s.name = ss.name ON CONFLICT (roadmap_node_id, skill_id) DO NOTHING;

-- Node-resource mappings.
DROP TABLE IF EXISTS seed_node_resource;
-- Choice group resources are intentionally pushed down to actionable child nodes; computed group nodes should not carry learning resources.
CREATE TEMP TABLE seed_node_resource (node_key text NOT NULL, resource_key text NOT NULL, order_index int NOT NULL) ON COMMIT DROP;
;

WITH deduped_node_resource AS (
    SELECT DISTINCT ON (rn.roadmap_node_id, lr.learning_resource_id)
        rn.roadmap_node_id,
        lr.learning_resource_id AS learning_resource_id,
        snr.order_index,
        (snr.order_index <= 3) AS is_primary
    FROM seed_node_resource snr
JOIN seed_node sn ON sn.node_key = snr.node_key
JOIN seed_roadmap_map m ON true
JOIN public.roadmap_node rn ON rn.roadmap_version_id = m.roadmap_version_id AND rn.slug = sn.node_key
JOIN seed_resource sr ON sr.resource_key = snr.resource_key
JOIN public.learning_resource lr ON lr.url = sr.url
    ORDER BY rn.roadmap_node_id, lr.learning_resource_id, snr.order_index
)
SELECT roadmap_node_id, learning_resource_id, order_index, is_primary
FROM deduped_node_resource
ON CONFLICT (roadmap_node_id, learning_resource_id) DO UPDATE SET
    order_index = EXCLUDED.order_index,
    is_primary = EXCLUDED.is_primary;

SELECT DISTINCT lr.learning_resource_id, s.skill_id FROM seed_node_resource snr JOIN seed_node_skill sns ON sns.node_key = snr.node_key JOIN seed_resource sr ON sr.resource_key = snr.resource_key JOIN public.learning_resource lr ON lr.url = sr.url JOIN seed_skill ss ON ss.slug = sns.skill_slug JOIN public.skill s ON s.slug = ss.slug OR s.name = ss.name ON CONFLICT (learning_resource_id, skill_id) DO NOTHING;

-- Roadmap edges.
DROP TABLE IF EXISTS seed_edge;
CREATE TEMP TABLE seed_edge (from_key text NOT NULL, to_key text NOT NULL, edge_type text NOT NULL, dependency_type text NOT NULL, condition jsonb NOT NULL) ON COMMIT DROP;

SELECT m.roadmap_version_id, source.roadmap_node_id, target.roadmap_node_id, se.edge_type, se.dependency_type, se.condition FROM seed_edge se CROSS JOIN seed_roadmap_map m JOIN public.roadmap_node source ON source.roadmap_version_id = m.roadmap_version_id AND source.slug = se.from_key JOIN public.roadmap_node target ON target.roadmap_version_id = m.roadmap_version_id AND target.slug = se.to_key ON CONFLICT (roadmap_version_id, from_node_id, to_node_id, edge_type) DO UPDATE SET dependency_type = EXCLUDED.dependency_type, condition = EXCLUDED.condition;

COMMIT;

-- Summary: Skills 246, Learning resources 80, Roadmap nodes 232, Node-skill mappings 246, Node-resource mappings 1483, Edges 276, Required trackable hours 418, All trackable hours 482, Roadmap estimated_total_hours 420.